import torch

def generate_inputs(axes_and_scalars, device):
    M = axes_and_scalars['M']
    K = axes_and_scalars['K']
    N = axes_and_scalars['N']
    A = torch.randn(M, K, dtype=torch.float32, device=device) / K ** 0.5
    B = torch.randn(K, N, dtype=torch.float32, device=device) / K ** 0.5
    return {'A': A, 'B': B}

@torch.no_grad()
def run(A, B):
    return A @ B
